mapper.select:
SELECT t.* FROM group_buy_team t
WHERE t.activity_id = #{activityId}
  AND t.product_id = #{productId}
  AND t.status = 0
  AND t.current_people < t.required_people
  AND t.end_time > NOW()

    AND NOT EXISTS (
        SELECT 1 FROM group_buy_team_member m
        WHERE m.team_id = t.team_id
          AND m.user_id = #{userId}
    )

ORDER BY t.current_people DESC, t.create_time ASC
